1	//! The implementation is based on Dmitry Vyukov's bounded MPMC queue.
2	//!
3	//! Source:
4	//!   - <http://www.1024cores.net/home/lock-free-algorithms/queues/bounded-mpmc-queue>
5	
6	use alloc::boxed::Box;
7	use core::{
8	    cell::UnsafeCell,
9	    fmt,
10	    mem::{self, MaybeUninit},
11	    panic::{RefUnwindSafe, UnwindSafe},
12	    sync::atomic::{self, AtomicUsize, Ordering},
13	};
14	
15	use crossbeam_utils::{Backoff, CachePadded};
16	
17	/// A slot in a queue.
18	struct Slot<T> {
19	    /// The current stamp.
20	    ///
21	    /// If the stamp equals the tail, this node will be next written to. If it equals head + 1,
22	    /// this node will be next read from.
23	    stamp: AtomicUsize,
24	
25	    /// The value in this slot.
26	    value: UnsafeCell<MaybeUninit<T>>,
27	}
28	
29	/// A bounded multi-producer multi-consumer queue.
30	///
31	/// This queue allocates a fixed-capacity buffer on construction, which is used to store pushed
32	/// elements. The queue cannot hold more elements than the buffer allows. Attempting to push an
33	/// element into a full queue will fail. Alternatively, [`force_push`] makes it possible for
34	/// this queue to be used as a ring-buffer. Having a buffer allocated upfront makes this queue
35	/// a bit faster than [`SegQueue`].
36	///
37	/// [`force_push`]: ArrayQueue::force_push
38	/// [`SegQueue`]: super::SegQueue
39	///
40	/// # Examples
41	///
42	/// ```
43	/// use crossbeam_queue::ArrayQueue;
44	///
45	/// let q = ArrayQueue::new(2);
46	///
47	/// assert_eq!(q.push('a'), Ok(()));
48	/// assert_eq!(q.push('b'), Ok(()));
49	/// assert_eq!(q.push('c'), Err('c'));
50	/// assert_eq!(q.pop(), Some('a'));
51	/// ```
52	pub struct ArrayQueue<T> {
53	    /// The head of the queue.
54	    ///
55	    /// This value is a "stamp" consisting of an index into the buffer and a lap, but packed into a
56	    /// single `usize`. The lower bits represent the index, while the upper bits represent the lap.
57	    ///
58	    /// Elements are popped from the head of the queue.
59	    head: CachePadded<AtomicUsize>,
60	
61	    /// The tail of the queue.
62	    ///
63	    /// This value is a "stamp" consisting of an index into the buffer and a lap, but packed into a
64	    /// single `usize`. The lower bits represent the index, while the upper bits represent the lap.
65	    ///
66	    /// Elements are pushed into the tail of the queue.
67	    tail: CachePadded<AtomicUsize>,
68	
69	    /// The buffer holding slots.
70	    buffer: Box<[Slot<T>]>,
71	
72	    /// A stamp with the value of `{ lap: 1, index: 0 }`.
73	    one_lap: usize,
74	}
75	
76	unsafe impl<T: Send> Sync for ArrayQueue<T> {}
77	unsafe impl<T: Send> Send for ArrayQueue<T> {}
78	
79	impl<T> UnwindSafe for ArrayQueue<T> {}
80	impl<T> RefUnwindSafe for ArrayQueue<T> {}
81	
82	impl<T> ArrayQueue<T> {
83	    /// Creates a new bounded queue with the given capacity.
84	    ///
85	    /// # Panics
86	    ///
87	    /// Panics if the capacity is zero.
88	    ///
89	    /// # Examples
90	    ///
91	    /// ```
92	    /// use crossbeam_queue::ArrayQueue;
93	    ///
94	    /// let q = ArrayQueue::<i32>::new(100);
95	    /// ```
96	    pub fn new(cap: usize) -> Self {
97	        assert!(cap > 0, "capacity must be non-zero");
98	
99	        // Head is initialized to `{ lap: 0, index: 0 }`.
100	        // Tail is initialized to `{ lap: 0, index: 0 }`.
101	        let head = 0;
102	        let tail = 0;
103	
104	        // Allocate a buffer of `cap` slots initialized
105	        // with stamps.
106	        let buffer: Box<[Slot<T>]> = (0..cap)
107	            .map(|i| {
108	                // Set the stamp to `{ lap: 0, index: i }`.
109	                Slot {
110	                    stamp: AtomicUsize::new(i),
111	                    value: UnsafeCell::new(MaybeUninit::uninit()),
112	                }
113	            })
114	            .collect();
115	
116	        // One lap is the smallest power of two greater than `cap`.
117	        let one_lap = (cap + 1).next_power_of_two();
118	
119	        Self {
120	            buffer,
121	            one_lap,
122	            head: CachePadded::new(AtomicUsize::new(head)),
123	            tail: CachePadded::new(AtomicUsize::new(tail)),
124	        }
125	    }
126	
127	    fn push_or_else<F>(&self, mut value: T, f: F) -> Result<(), T>
128	    where
129	        F: Fn(T, usize, usize, &Slot<T>) -> Result<T, T>,
130	    {
131	        let backoff = Backoff::new();
132	        let mut tail = self.tail.load(Ordering::Relaxed);
133	
134	        loop {
135	            // Deconstruct the tail.
136	            let index = tail & (self.one_lap - 1);
137	            let lap = tail & !(self.one_lap - 1);
138	
139	            let new_tail = if index + 1 < self.capacity() {
140	                // Same lap, incremented index.
141	                // Set to `{ lap: lap, index: index + 1 }`.
142	                tail + 1
143	            } else {
144	                // One lap forward, index wraps around to zero.
145	                // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
146	                lap.wrapping_add(self.one_lap)
147	            };
148	
149	            // Inspect the corresponding slot.
150	            debug_assert!(index < self.buffer.len());
151	            let slot = unsafe { self.buffer.get_unchecked(index) };
152	            let stamp = slot.stamp.load(Ordering::Acquire);
153	
154	            // If the tail and the stamp match, we may attempt to push.
155	            if tail == stamp {
156	                // Try moving the tail.
157	                match self.tail.compare_exchange_weak(
158	                    tail,
159	                    new_tail,
160	                    Ordering::SeqCst,
161	                    Ordering::Relaxed,
162	                ) {
163	                    Ok(_) => {
164	                        // Write the value into the slot and update the stamp.
165	                        unsafe {
166	                            slot.value.get().write(MaybeUninit::new(value));
167	                        }
168	                        slot.stamp.store(tail + 1, Ordering::Release);
169	                        return Ok(());
170	                    }
171	                    Err(t) => {
172	                        tail = t;
173	                        backoff.spin();
174	                    }
175	                }
176	            } else if stamp.wrapping_add(self.one_lap) == tail + 1 {
177	                atomic::fence(Ordering::SeqCst);
178	                value = f(value, tail, new_tail, slot)?;
179	                backoff.spin();
180	                tail = self.tail.load(Ordering::Relaxed);
181	            } else {
182	                // Snooze because we need to wait for the stamp to get updated.
183	                backoff.snooze();
184	                tail = self.tail.load(Ordering::Relaxed);
185	            }
186	        }
187	    }
188	
189	    /// Attempts to push an element into the queue.
190	    ///
191	    /// If the queue is full, the element is returned back as an error.
192	    ///
193	    /// # Examples
194	    ///
195	    /// ```
196	    /// use crossbeam_queue::ArrayQueue;
197	    ///
198	    /// let q = ArrayQueue::new(1);
199	    ///
200	    /// assert_eq!(q.push(10), Ok(()));
201	    /// assert_eq!(q.push(20), Err(20));
202	    /// ```
203	    pub fn push(&self, value: T) -> Result<(), T> {
204	        self.push_or_else(value, |v, tail, _, _| {
205	            let head = self.head.load(Ordering::Relaxed);
206	
207	            // If the head lags one lap behind the tail as well...
208	            if head.wrapping_add(self.one_lap) == tail {
209	                // ...then the queue is full.
210	                Err(v)
211	            } else {
212	                Ok(v)
213	            }
214	        })
215	    }
216	
217	    /// Attempts to push an element using an exclusive reference of the queue.
218	    ///
219	    /// Atomic operations and checks are omitted
220	    ///
221	    /// # Examples
222	    ///
223	    /// ```
224	    /// use crossbeam_queue::ArrayQueue;
225	    ///
226	    /// let mut q = ArrayQueue::new(1);
227	    ///
228	    /// assert_eq!(q.push_mut(10), Ok(()));
229	    /// assert_eq!(q.push_mut(20), Err(20));
230	    /// ```
231	    pub fn push_mut(&mut self, value: T) -> Result<(), T> {
232	        let tail = *self.tail.get_mut();
233	        let head = *self.head.get_mut();
234	
235	        if head.wrapping_add(self.one_lap) == tail {
236	            return Err(value);
237	        }
238	
239	        let index = tail & (self.one_lap - 1);
240	        let lap = tail & !(self.one_lap - 1);
241	        let new_tail = if index + 1 < self.capacity() {
242	            tail + 1
243	        } else {
244	            lap.wrapping_add(self.one_lap)
245	        };
246	
247	        *self.tail.get_mut() = new_tail;
248	
249	        let slot = unsafe { self.buffer.get_unchecked_mut(index) };
250	        unsafe {
251	            slot.value.get().write(MaybeUninit::new(value));
252	        }
253	        *slot.stamp.get_mut() = tail + 1;
254	
255	        Ok(())
256	    }
257	
258	    /// Pushes an element into the queue, replacing the oldest element if necessary.
259	    ///
260	    /// If the queue is full, the oldest element is replaced and returned,
261	    /// otherwise `None` is returned.
262	    ///
263	    /// # Examples
264	    ///
265	    /// ```
266	    /// use crossbeam_queue::ArrayQueue;
267	    ///
268	    /// let q = ArrayQueue::new(2);
269	    ///
270	    /// assert_eq!(q.force_push(10), None);
271	    /// assert_eq!(q.force_push(20), None);
272	    /// assert_eq!(q.force_push(30), Some(10));
273	    /// assert_eq!(q.pop(), Some(20));
274	    /// ```
275	    pub fn force_push(&self, value: T) -> Option<T> {
276	        self.push_or_else(value, |v, tail, new_tail, slot| {
277	            let head = tail.wrapping_sub(self.one_lap);
278	            let new_head = new_tail.wrapping_sub(self.one_lap);
279	
280	            // Try moving the head.
281	            if self
282	                .head
283	                .compare_exchange_weak(head, new_head, Ordering::SeqCst, Ordering::Relaxed)
284	                .is_ok()
285	            {
286	                // Move the tail.
287	                self.tail.store(new_tail, Ordering::SeqCst);
288	
289	                // Swap the previous value.
290	                let old = unsafe { slot.value.get().replace(MaybeUninit::new(v)).assume_init() };
291	
292	                // Update the stamp.
293	                slot.stamp.store(tail + 1, Ordering::Release);
294	
295	                Err(old)
296	            } else {
297	                Ok(v)
298	            }
299	        })
300	        .err()
301	    }
302	
303	    /// Attempts to pop an element from the queue.
304	    ///
305	    /// If the queue is empty, `None` is returned.
306	    ///
307	    /// # Examples
308	    ///
309	    /// ```
310	    /// use crossbeam_queue::ArrayQueue;
311	    ///
312	    /// let q = ArrayQueue::new(1);
313	    /// assert_eq!(q.push(10), Ok(()));
314	    ///
315	    /// assert_eq!(q.pop(), Some(10));
316	    /// assert!(q.pop().is_none());
317	    /// ```
318	    pub fn pop(&self) -> Option<T> {
319	        let backoff = Backoff::new();
320	        let mut head = self.head.load(Ordering::Relaxed);
321	
322	        loop {
323	            // Deconstruct the head.
324	            let index = head & (self.one_lap - 1);
325	            let lap = head & !(self.one_lap - 1);
326	
327	            // Inspect the corresponding slot.
328	            debug_assert!(index < self.buffer.len());
329	            let slot = unsafe { self.buffer.get_unchecked(index) };
330	            let stamp = slot.stamp.load(Ordering::Acquire);
331	
332	            // If the stamp is ahead of the head by 1, we may attempt to pop.
333	            if head + 1 == stamp {
334	                let new = if index + 1 < self.capacity() {
335	                    // Same lap, incremented index.
336	                    // Set to `{ lap: lap, index: index + 1 }`.
337	                    head + 1
338	                } else {
339	                    // One lap forward, index wraps around to zero.
340	                    // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
341	                    lap.wrapping_add(self.one_lap)
342	                };
343	
344	                // Try moving the head.
345	                match self.head.compare_exchange_weak(
346	                    head,
347	                    new,
348	                    Ordering::SeqCst,
349	                    Ordering::Relaxed,
350	                ) {
351	                    Ok(_) => {
352	                        // Read the value from the slot and update the stamp.
353	                        let msg = unsafe { slot.value.get().read().assume_init() };
354	                        slot.stamp
355	                            .store(head.wrapping_add(self.one_lap), Ordering::Release);
356	                        return Some(msg);
357	                    }
358	                    Err(h) => {
359	                        head = h;
360	                        backoff.spin();
361	                    }
362	                }
363	            } else if stamp == head {
364	                atomic::fence(Ordering::SeqCst);
365	                let tail = self.tail.load(Ordering::Relaxed);
366	
367	                // If the tail equals the head, that means the channel is empty.
368	                if tail == head {
369	                    return None;
370	                }
371	
372	                backoff.spin();
373	                head = self.head.load(Ordering::Relaxed);
374	            } else {
375	                // Snooze because we need to wait for the stamp to get updated.
376	                backoff.snooze();
377	                head = self.head.load(Ordering::Relaxed);
378	            }
379	        }
380	    }
381	
382	    /// Attempts to pop an element using an exclusive reference of the queue.
383	    ///
384	    /// Due to having an exclusive reference, atomic operations and checks are omitted
385	    ///
386	    /// # Examples
387	    ///
388	    /// ```
389	    /// use crossbeam_queue::ArrayQueue;
390	    ///
391	    /// let mut q = ArrayQueue::new(1);
392	    /// assert_eq!(q.push(10), Ok(()));
393	    ///
394	    /// assert_eq!(q.pop_mut(), Some(10));
395	    /// assert!(q.pop_mut().is_none());
396	    /// ```
397	    pub fn pop_mut(&mut self) -> Option<T> {
398	        let head = *self.head.get_mut();
399	        let tail = *self.tail.get_mut();
400	
401	        // If the tail equals the head, that means the channel is empty.
402	        if tail == head {
403	            return None;
404	        }
405	        let index = head & (self.one_lap - 1);
406	        let lap = head & !(self.one_lap - 1);
407	
408	        // Inspect the corresponding slot.
409	        debug_assert!(index < self.buffer.len());
410	
411	        let new = if index + 1 < self.capacity() {
412	            // Same lap, incremented index.
413	            // Set to `{ lap: lap, index: index + 1 }`.
414	            head + 1
415	        } else {
416	            // One lap forward, index wraps around to zero.
417	            // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
418	            lap.wrapping_add(self.one_lap)
419	        };
420	
421	        let slot = unsafe { self.buffer.get_unchecked_mut(index) };
422	
423	        let msg = unsafe { slot.value.get().read().assume_init() };
424	        *slot.stamp.get_mut() = head.wrapping_add(self.one_lap);
425	        *self.head.get_mut() = new;
426	        Some(msg)
427	    }
428	
429	    /// Returns the capacity of the queue.
430	    ///
431	    /// # Examples
432	    ///
433	    /// ```
434	    /// use crossbeam_queue::ArrayQueue;
435	    ///
436	    /// let q = ArrayQueue::<i32>::new(100);
437	    ///
438	    /// assert_eq!(q.capacity(), 100);
439	    /// ```
440	    #[inline]
441	    pub fn capacity(&self) -> usize {
442	        self.buffer.len()
443	    }
444	
445	    /// Returns `true` if the queue is empty.
446	    ///
447	    /// # Examples
448	    ///
449	    /// ```
450	    /// use crossbeam_queue::ArrayQueue;
451	    ///
452	    /// let q = ArrayQueue::new(100);
453	    ///
454	    /// assert!(q.is_empty());
455	    /// q.push(1).unwrap();
456	    /// assert!(!q.is_empty());
457	    /// ```
458	    pub fn is_empty(&self) -> bool {
459	        let head = self.head.load(Ordering::SeqCst);
460	        let tail = self.tail.load(Ordering::SeqCst);
461	
462	        // Is the tail lagging one lap behind head?
463	        // Is the tail equal to the head?
464	        //
465	        // Note: If the head changes just before we load the tail, that means there was a moment
466	        // when the channel was not empty, so it is safe to just return `false`.
467	        tail == head
468	    }
469	
470	    /// Returns `true` if the queue is full.
471	    ///
472	    /// # Examples
473	    ///
474	    /// ```
475	    /// use crossbeam_queue::ArrayQueue;
476	    ///
477	    /// let q = ArrayQueue::new(1);
478	    ///
479	    /// assert!(!q.is_full());
480	    /// q.push(1).unwrap();
481	    /// assert!(q.is_full());
482	    /// ```
483	    pub fn is_full(&self) -> bool {
484	        let tail = self.tail.load(Ordering::SeqCst);
485	        let head = self.head.load(Ordering::SeqCst);
486	
487	        // Is the head lagging one lap behind tail?
488	        //
489	        // Note: If the tail changes just before we load the head, that means there was a moment
490	        // when the queue was not full, so it is safe to just return `false`.
491	        head.wrapping_add(self.one_lap) == tail
492	    }
493	
494	    /// Returns the number of elements in the queue.
495	    ///
496	    /// # Examples
497	    ///
498	    /// ```
499	    /// use crossbeam_queue::ArrayQueue;
500	    ///
501	    /// let q = ArrayQueue::new(100);
502	    /// assert_eq!(q.len(), 0);
503	    ///
504	    /// q.push(10).unwrap();
505	    /// assert_eq!(q.len(), 1);
506	    ///
507	    /// q.push(20).unwrap();
508	    /// assert_eq!(q.len(), 2);
509	    /// ```
510	    pub fn len(&self) -> usize {
511	        loop {
512	            // Load the tail, then load the head.
513	            let tail = self.tail.load(Ordering::SeqCst);
514	            let head = self.head.load(Ordering::SeqCst);
515	
516	            // If the tail didn't change, we've got consistent values to work with.
517	            if self.tail.load(Ordering::SeqCst) == tail {
518	                let hix = head & (self.one_lap - 1);
519	                let tix = tail & (self.one_lap - 1);
520	
521	                return if hix < tix {
522	                    tix - hix
523	                } else if hix > tix {
524	                    self.capacity() - hix + tix
525	                } else if tail == head {
526	                    0
527	                } else {
528	                    self.capacity()
529	                };
530	            }
531	        }
532	    }
533	}
534	
535	impl<T> Drop for ArrayQueue<T> {
536	    fn drop(&mut self) {
537	        if mem::needs_drop::<T>() {
538	            // Get the index of the head.
539	            let head = *self.head.get_mut();
540	            let tail = *self.tail.get_mut();
541	
542	            let hix = head & (self.one_lap - 1);
543	            let tix = tail & (self.one_lap - 1);
544	
545	            let len = if hix < tix {
546	                tix - hix
547	            } else if hix > tix {
548	                self.capacity() - hix + tix
549	            } else if tail == head {
550	                0
551	            } else {
552	                self.capacity()
553	            };
554	
555	            // Loop over all slots that hold a message and drop them.
556	            for i in 0..len {
557	                // Compute the index of the next slot holding a message.
558	                let index = if hix + i < self.capacity() {
559	                    hix + i
560	                } else {
561	                    hix + i - self.capacity()
562	                };
563	
564	                unsafe {
565	                    debug_assert!(index < self.buffer.len());
566	                    let slot = self.buffer.get_unchecked_mut(index);
567	                    (*slot.value.get()).assume_init_drop();
568	                }
569	            }
570	        }
571	    }
572	}
573	
574	impl<T> fmt::Debug for ArrayQueue<T> {
575	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
576	        f.pad("ArrayQueue { .. }")
577	    }
578	}
579	
580	impl<T> IntoIterator for ArrayQueue<T> {
581	    type Item = T;
582	
583	    type IntoIter = IntoIter<T>;
584	
585	    fn into_iter(self) -> Self::IntoIter {
586	        IntoIter { value: self }
587	    }
588	}
589	
590	#[derive(Debug)]
591	pub struct IntoIter<T> {
592	    value: ArrayQueue<T>,
593	}
594	
595	impl<T> Iterator for IntoIter<T> {
596	    type Item = T;
597	
598	    fn next(&mut self) -> Option<Self::Item> {
599	        let value = &mut self.value;
600	        let head = *value.head.get_mut();
601	        if value.head.get_mut() != value.tail.get_mut() {
602	            let index = head & (value.one_lap - 1);
603	            let lap = head & !(value.one_lap - 1);
604	            // SAFETY: We have mutable access to this, so we can read without
605	            // worrying about concurrency. Furthermore, we know this is
606	            // initialized because it is the value pointed at by `value.head`
607	            // and this is a non-empty queue.
608	            let val = unsafe {
609	                debug_assert!(index < value.buffer.len());
610	                let slot = value.buffer.get_unchecked_mut(index);
611	                slot.value.get().read().assume_init()
612	            };
613	            let new = if index + 1 < value.capacity() {
614	                // Same lap, incremented index.
615	                // Set to `{ lap: lap, index: index + 1 }`.
616	                head + 1
617	            } else {
618	                // One lap forward, index wraps around to zero.
619	                // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
620	                lap.wrapping_add(value.one_lap)
621	            };
622	            *value.head.get_mut() = new;
623	            Some(val)
624	        } else {
625	            None
626	        }
627	    }
628	}
