180	    ///
181	    /// # Examples
182	    ///
183	    /// ```
184	    /// use crossbeam_queue::SegQueue;
185	    ///
186	    /// let q = SegQueue::<i32>::new();
187	    /// ```
188	    pub const fn new() -> Self {
189	        Self {
190	            head: CachePadded::new(Position {
191	                block: AtomicPtr::new(ptr::null_mut()),
192	                index: AtomicUsize::new(0),
193	            }),
194	            tail: CachePadded::new(Position {
195	                block: AtomicPtr::new(ptr::null_mut()),
196	                index: AtomicUsize::new(0),
197	            }),
198	            _marker: PhantomData,
199	        }
200	    }
201	
202	    /// Pushes back an element to the tail.
203	    ///
204	    /// # Examples
205	    ///
206	    /// ```
207	    /// use crossbeam_queue::SegQueue;
208	    ///
209	    /// let q = SegQueue::new();
210	    ///
211	    /// q.push(10);
212	    /// q.push(20);
213	    /// ```
214	    pub fn push(&self, value: T) {
215	        let backoff = Backoff::new();
216	        let mut tail = self.tail.index.load(Ordering::Acquire);
217	        let mut block = self.tail.block.load(Ordering::Acquire);
218	        let mut next_block = None;
219	
220	        loop {
221	            // Calculate the offset of the index into the block.
222	            let offset = (tail >> SHIFT) % LAP;
223	
224	            // If we reached the end of the block, wait until the next one is installed.
225	            if offset == BLOCK_CAP {
226	                backoff.snooze();
227	                tail = self.tail.index.load(Ordering::Acquire);
228	                block = self.tail.block.load(Ordering::Acquire);
229	                continue;
230	            }
231	
232	            // If we're going to have to install the next block, allocate it in advance in order to
233	            // make the wait for other threads as short as possible.
234	            if offset + 1 == BLOCK_CAP && next_block.is_none() {
235	                next_block = Some(Block::<T>::new());
236	            }
237	
238	            // If this is the first push operation, we need to allocate the first block.
239	            if block.is_null() {
240	                let new = Box::into_raw(Block::<T>::new());
241	
242	                if self
243	                    .tail
244	                    .block
245	                    .compare_exchange(block, new, Ordering::Release, Ordering::Relaxed)
246	                    .is_ok()
247	                {
248	                    self.head.block.store(new, Ordering::Release);
249	                    block = new;
250	                } else {
251	                    next_block = unsafe { Some(Box::from_raw(new)) };
252	                    tail = self.tail.index.load(Ordering::Acquire);
253	                    block = self.tail.block.load(Ordering::Acquire);
254	                    continue;
255	                }
256	            }
257	
258	            let new_tail = tail + (1 << SHIFT);
259	
260	            // Try advancing the tail forward.
261	            match self.tail.index.compare_exchange_weak(
262	                tail,
263	                new_tail,
264	                Ordering::SeqCst,
265	                Ordering::Acquire,
266	            ) {
267	                Ok(_) => unsafe {
268	                    // If we've reached the end of the block, install the next one.
269	                    if offset + 1 == BLOCK_CAP {
270	                        let next_block = Box::into_raw(next_block.unwrap());
271	                        let next_index = new_tail.wrapping_add(1 << SHIFT);
272	
273	                        self.tail.block.store(next_block, Ordering::Release);
274	                        self.tail.index.store(next_index, Ordering::Release);
275	                        (*block).next.store(next_block, Ordering::Release);
276	                    }
277	
278	                    // Write the value into the slot.
279	                    let slot = (*block).slots.get_unchecked(offset);
280	                    slot.value.get().write(MaybeUninit::new(value));
281	                    slot.state.fetch_or(WRITE, Ordering::Release);
282	
283	                    return;
284	                },
285	                Err(t) => {
286	                    tail = t;
287	                    block = self.tail.block.load(Ordering::Acquire);
288	                    backoff.spin();
289	                }
290	            }
291	        }
292	    }
293	
294	    /// Pushes an element to the queue with exclusive mutable access.
295	    ///
296	    /// Avoids atomic operations and synchronization, assuming
297	    /// no other threads access the queue concurrently.
298	    ///
299	    /// # Examples
300	    ///
301	    /// ```
302	    /// use crossbeam_queue::SegQueue;
303	    ///
304	    /// let mut q = SegQueue::new();
305	    ///
306	    /// q.push_mut(10);
307	    /// q.push_mut(20);
308	    /// ```
309	    pub fn push_mut(&mut self, value: T) {
310	        let tail = *self.tail.index.get_mut();
311	        let mut block = *self.tail.block.get_mut();
312	
313	        // Calculate the offset of the index into the block.
314	        let offset = (tail >> SHIFT) % LAP;
315	
316	        // If this is the first push operation, we need to allocate the first block.
317	        if block.is_null() {
318	            let new = Box::into_raw(Block::<T>::new());
319	            *self.head.block.get_mut() = new;
320	            *self.tail.block.get_mut() = new;
321	
322	            block = new;
323	        }
324	
325	        let new_tail = tail + (1 << SHIFT);
326	
327	        *self.tail.index.get_mut() = new_tail;
328	
329	        unsafe {
330	            // If we've reached the end of the block, install the next one.
331	            if offset + 1 == BLOCK_CAP {
332	                let next_block = Box::into_raw(Block::<T>::new());
333	                let next_index = new_tail.wrapping_add(1 << SHIFT);
334	
335	                *self.tail.block.get_mut() = next_block;
336	                *self.tail.index.get_mut() = next_index;
337	                *(*block).next.get_mut() = next_block;
338	            }
339	
340	            // Write the value into the slot.
341	            let slot = (*block).slots.get_unchecked(offset);
342	            slot.value.get().write(MaybeUninit::new(value));
343	            *(*block).slots.get_unchecked_mut(offset).state.get_mut() |= WRITE;
344	        }
345	    }
346	
347	    /// Pops the head element from the queue.
348	    ///
349	    /// If the queue is empty, `None` is returned.
350	    ///
351	    /// # Examples
352	    ///
353	    /// ```
354	    /// use crossbeam_queue::SegQueue;
355	    ///
356	    /// let q = SegQueue::new();
357	    ///
358	    /// q.push(10);
359	    /// q.push(20);
360	    /// assert_eq!(q.pop(), Some(10));
361	    /// assert_eq!(q.pop(), Some(20));
362	    /// assert!(q.pop().is_none());
363	    /// ```
364	    pub fn pop(&self) -> Option<T> {
365	        let backoff = Backoff::new();
366	        let mut head = self.head.index.load(Ordering::Acquire);
367	        let mut block = self.head.block.load(Ordering::Acquire);
368	
369	        loop {
370	            // Calculate the offset of the index into the block.
371	            let offset = (head >> SHIFT) % LAP;
372	
373	            // If we reached the end of the block, wait until the next one is installed.
374	            if offset == BLOCK_CAP {
375	                backoff.snooze();
376	                head = self.head.index.load(Ordering::Acquire);
377	                block = self.head.block.load(Ordering::Acquire);
378	                continue;
379	            }
380	
381	            let mut new_head = head + (1 << SHIFT);
382	
383	            if new_head & HAS_NEXT == 0 {
384	                atomic::fence(Ordering::SeqCst);
385	                let tail = self.tail.index.load(Ordering::Relaxed);
386	
387	                // If the tail equals the head, that means the queue is empty.
388	                if head >> SHIFT == tail >> SHIFT {
389	                    return None;
390	                }
391	
392	                // If head and tail are not in the same block, set `HAS_NEXT` in head.
393	                if (head >> SHIFT) / LAP != (tail >> SHIFT) / LAP {
394	                    new_head |= HAS_NEXT;
395	                }
396	            }
397	
398	            // The block can be null here only if the first push operation is in progress. In that
399	            // case, just wait until it gets initialized.
400	            if block.is_null() {
401	                backoff.snooze();
402	                head = self.head.index.load(Ordering::Acquire);
403	                block = self.head.block.load(Ordering::Acquire);
404	                continue;
405	            }
406	
407	            // Try moving the head index forward.
408	            match self.head.index.compare_exchange_weak(
409	                head,
410	                new_head,
411	                Ordering::SeqCst,
412	                Ordering::Acquire,
413	            ) {
414	                Ok(_) => unsafe {
415	                    // If we've reached the end of the block, move to the next one.
416	                    if offset + 1 == BLOCK_CAP {
417	                        let next = (*block).wait_next();
418	                        let mut next_index = (new_head & !HAS_NEXT).wrapping_add(1 << SHIFT);
419	                        if !(*next).next.load(Ordering::Relaxed).is_null() {
420	                            next_index |= HAS_NEXT;
421	                        }
422	
423	                        self.head.block.store(next, Ordering::Release);
424	                        self.head.index.store(next_index, Ordering::Release);
425	                    }
426	
427	                    // Read the value.
428	                    let slot = (*block).slots.get_unchecked(offset);
429	                    slot.wait_write();
430	                    let value = slot.value.get().read().assume_init();
431	
432	                    // Destroy the block if we've reached the end, or if another thread wanted to
433	                    // destroy but couldn't because we were busy reading from the slot.
434	                    if offset + 1 == BLOCK_CAP {
435	                        Block::destroy(block, 0);
436	                    } else if slot.state.fetch_or(READ, Ordering::AcqRel) & DESTROY != 0 {
437	                        Block::destroy(block, offset + 1);
438	                    }
439	
440	                    return Some(value);
441	                },
442	                Err(h) => {
443	                    head = h;
444	                    block = self.head.block.load(Ordering::Acquire);
445	                    backoff.spin();
446	                }
447	            }
448	        }
449	    }
450	
451	    /// Pops the head element from the queue using an exclusive reference.
452	    ///
453	    /// Avoids atomic operations and synchronization, assuming
454	    /// no other threads access the queue concurrently.
455	    ///
456	    /// If the queue is empty, `None` is returned.
457	    ///
458	    /// # Examples
459	    ///
460	    /// ```
461	    /// use crossbeam_queue::SegQueue;
462	    ///
463	    /// let mut q = SegQueue::new();
464	    ///
465	    /// q.push(10);
466	    /// q.push(20);
467	    /// assert_eq!(q.pop_mut(), Some(10));
468	    /// assert_eq!(q.pop_mut(), Some(20));
469	    /// assert!(q.pop_mut().is_none());
470	    /// ```
471	    pub fn pop_mut(&mut self) -> Option<T> {
472	        let head = *self.head.index.get_mut();
473	        let block = *self.head.block.get_mut();
474	
475	        // Calculate the offset of the index into the block.
476	        let offset = (head >> SHIFT) % LAP;
477	
478	        let mut new_head = head + (1 << SHIFT);
479	
480	        if new_head & HAS_NEXT == 0 {
481	            let tail = *self.tail.index.get_mut();
482	
483	            // If the tail equals the head, that means the queue is empty.
484	            if head >> SHIFT == tail >> SHIFT {
485	                return None;
486	            }
487	
488	            // If head and tail are not in the same block, set `HAS_NEXT` in head.
489	            if (head >> SHIFT) / LAP != (tail >> SHIFT) / LAP {
490	                new_head |= HAS_NEXT;
491	            }
492	        }
493	
494	        *self.head.index.get_mut() = new_head;
495	
496	        unsafe {
497	            // If we've reached the end of the block, move to the next one.
498	            if offset + 1 == BLOCK_CAP {
499	                let next = *(*block).next.get_mut();
500	                let mut next_index = (new_head & !HAS_NEXT).wrapping_add(1 << SHIFT);
501	                if !(*next).next.get_mut().is_null() {
502	                    next_index |= HAS_NEXT;
503	                }
504	
505	                *self.head.block.get_mut() = next;
506	                *self.head.index.get_mut() = next_index;
507	            }
508	
509	            // Read the value.
510	            let slot = (*block).slots.get_unchecked(offset);
511	            let value = slot.value.get().read().assume_init();
512	
513	            // Destroy the block if we've reached the end
514	            if offset + 1 == BLOCK_CAP {
515	                Block::destroy_mut(block);
516	            } else {
517	                let state = *(*block).slots.get_unchecked_mut(offset).state.get_mut();
518	                *(*block).slots.get_unchecked_mut(offset).state.get_mut() = state | READ;
519	                if state & DESTROY != 0 {
520	                    Block::destroy(block, offset + 1);
521	                }
522	            }
523	
524	            Some(value)
525	        }
526	    }
527	
528	    /// Returns `true` if the queue is empty.
529	    ///
530	    /// # Examples
531	    ///
532	    /// ```
533	    /// use crossbeam_queue::SegQueue;
534	    ///
535	    /// let q = SegQueue::new();
536	    ///
537	    /// assert!(q.is_empty());
538	    /// q.push(1);
539	    /// assert!(!q.is_empty());
540	    /// ```
541	    pub fn is_empty(&self) -> bool {
542	        let head = self.head.index.load(Ordering::SeqCst);
543	        let tail = self.tail.index.load(Ordering::SeqCst);
544	        head >> SHIFT == tail >> SHIFT
545	    }
546	
547	    /// Returns the number of elements in the queue.
548	    ///
549	    /// # Examples
550	    ///
551	    /// ```
552	    /// use crossbeam_queue::SegQueue;
553	    ///
554	    /// let q = SegQueue::new();
555	    /// assert_eq!(q.len(), 0);
556	    ///
557	    /// q.push(10);
558	    /// assert_eq!(q.len(), 1);
559	    ///
560	    /// q.push(20);
561	    /// assert_eq!(q.len(), 2);
562	    /// ```
563	    pub fn len(&self) -> usize {
564	        loop {
565	            // Load the tail index, then load the head index.
566	            let mut tail = self.tail.index.load(Ordering::SeqCst);
567	            let mut head = self.head.index.load(Ordering::SeqCst);
568	
569	            // If the tail index didn't change, we've got consistent indices to work with.
570	            if self.tail.index.load(Ordering::SeqCst) == tail {
571	                // Erase the lower bits.
572	                tail &= !((1 << SHIFT) - 1);
573	                head &= !((1 << SHIFT) - 1);
574	
575	                // Fix up indices if they fall onto block ends.
576	                if (tail >> SHIFT) & (LAP - 1) == LAP - 1 {
577	                    tail = tail.wrapping_add(1 << SHIFT);
578	                }
579	                if (head >> SHIFT) & (LAP - 1) == LAP - 1 {
580	                    head = head.wrapping_add(1 << SHIFT);
581	                }
582	
583	                // Rotate indices so that head falls into the first block.
584	                let lap = (head >> SHIFT) / LAP;
585	                tail = tail.wrapping_sub((lap * LAP) << SHIFT);
586	                head = head.wrapping_sub((lap * LAP) << SHIFT);
587	
588	                // Remove the lower bits.
589	                tail >>= SHIFT;
590	                head >>= SHIFT;
591	
592	                // Return the difference minus the number of blocks between tail and head.
593	                return tail - head - tail / LAP;
594	            }
595	        }
596	    }
597	}
